---@class ModelDefenceWar:LModel
local ModelDefenceWar      = LxClass("ModelDefenceWar", LModel)

local table                = table

ModelDefenceWar.MainFuncId = 16800000

function ModelDefenceWar:ModelDefenceWar()
    -- 当前活动Id
    self._activityId = 0

    -- 最大通关关卡
    self._passMaxStageId = 0

    -- 上阵信息
    self._formation = {}

    -- 少女信息
    self._heroMap = {}

    -- 下次恢复体力时间
    self._nextRecoverTime = 0

    self:InitRef()
end

function ModelDefenceWar:OnModelInit()
    self:ModelNetMsgRecv(LProtoIds.ProtectCityInfoResp, function(...) self:OnProtectCityInfoResp(...) end)
    self:ModelNetMsgRecv(LProtoIds.ProtectCityFormationResp, function(...) self:OnProtectCityFormationResp(...) end)
    self:ModelNetMsgRecv(LProtoIds.ProtectCityUpLevelHeroResp, function(...) self:OnProtectCityUpLevelHeroResp(...) end)
    self:ModelNetMsgRecv(LProtoIds.ProtectCityBattleResp, function(...) self:OnProtectCityBattleResp(...) end)
    self:ModelNetMsgRecv(LProtoIds.ProtectCityBattleResultResp, function(...) self:OnProtectCityBattleResultResp(...) end)

    self:ModelEventRecv(EventNames.ON_ACTIVITY_LIST_CHANGE, function(...) self:OnActivityListChange(...) end)
    self:ModelEventRecv(EventNames.ON_ACTIVITY_CONFIG_DATA, function(...) self:OnActivityConfigData(...) end)
end

--在协议数据处理完之后需要调用finish
function ModelDefenceWar:OnModelRequest()
    self:ModelFinish()
end

-- region 协议 ----------------------------------------------------

-- 查看保卫萌娘城数据 请求
function ModelDefenceWar:ProtectCityInfoReq(activityId)
    local pb = LProtoHelper.CreateProto(LProtoIds.ProtectCityInfoReq)
    pb.activityId = activityId or self._activityId
    SendMessage(pb, LProtoIds.ProtectCityInfoReq)
end

-- 查看保卫萌娘城数据 返回
function ModelDefenceWar:OnProtectCityInfoResp(pb)
    self._activityId = pb.activityId

    -- 关卡数据
    for _, v in ipairs(pb.barrierData) do
        if v.isPass == 1 then
            self._passMaxStageId = math.max(self._passMaxStageId, v.barrierId)
        end
    end

    -- 布阵数据
    self._formation = {}
    for _, v in ipairs(pb.formationData.siteData) do
        table.insert(self._formation, { site = v.site, heroId = v.hero.heroId })
    end

    -- 少女数据
    self._heroMap = {}
    for _, hero in ipairs(pb.heros) do
        self:SetHeroData(hero)
    end

    self._nextRecoverTime = pb.nextTime

    FireEvent(EventNames.DEFENCEWAR_BASE_INFO)
end

-- 设置英雄数据
function ModelDefenceWar:SetHeroData(hero)
    local heroLev = gModelDefenceWar:GetHeroLevByRefId(hero.level)
    local heroId = hero.heroId
    if not self._heroMap[heroId] then
        local tab = {}
        tab.heroId = heroId
        tab.lev = heroLev
        self._heroMap[tab.heroId] = tab
        return
    end
    self._heroMap[heroId].lev = heroLev
end

-- 升级英雄 请求
function ModelDefenceWar:ProtectCityUpLevelHeroReq(heroId, type, activityId)
    local pb = LProtoHelper.CreateProto(LProtoIds.ProtectCityUpLevelHeroReq)
    pb.activityId = activityId or self._activityId
    pb.type = type -- 类型 1-激活 2-升级
    pb.heroId = heroId
    SendMessage(pb, LProtoIds.ProtectCityUpLevelHeroReq)
end

-- 升级英雄 返回
function ModelDefenceWar:OnProtectCityUpLevelHeroResp(pb)
    self:SetHeroData(pb.hero)

    local heroLev = self:GetHeroLev(pb.hero.heroId)
    if heroLev == 1 then
        GF.OpenWnd("UIDefenceWarHeroActive", { heroId = pb.hero.heroId })
    end

    FireEvent(EventNames.DEFENCEWAR_BASE_INFO)
    FireEvent(EventNames.DEFENCEWAR_HERO_UP)
end

-- 布阵 请求
function ModelDefenceWar:ProtectCityFormationReq(list, activityId)
    local pb = LProtoHelper.CreateProto(LProtoIds.ProtectCityFormationReq)
    pb.activityId = activityId or self._activityId


    for pos, heroId in ipairs(list) do
        local data = pb.formation.siteData:add()
        data.site = pos
        data.hero.heroId = heroId

        local heroLev = self:GetHeroLev(heroId)
        local ref = self:GetHeroLevRef(heroId, heroLev)
        data.hero.level = ref.refId
    end

    SendMessage(pb, LProtoIds.ProtectCityFormationReq)
end

-- 布阵 返回
function ModelDefenceWar:OnProtectCityFormationResp(pb)
    self._formation = {}
    for _, v in ipairs(pb.formation.siteData) do
        table.insert(self._formation, { site = v.site, heroId = v.hero.heroId })
    end

    FireEvent(EventNames.DEFENCEWAR_FORMATION_CHANGE)
end

-- 开始战斗 请求
function ModelDefenceWar:ProtectCityBattleReq(barrierId, activityId)
    local pb = LProtoHelper.CreateProto(LProtoIds.ProtectCityBattleReq)
    pb.activityId = activityId or self._activityId
    pb.barrierId = barrierId

    SendMessage(pb, LProtoIds.ProtectCityBattleReq)
end

-- 开始战斗 返回
function ModelDefenceWar:OnProtectCityBattleResp(pb)
    local barrierId = pb.barrierId

    gModelDefenceWar:EnterMap(barrierId)
end

-- 战斗结果 请求
function ModelDefenceWar:ProtectCityBattleResultReq(barrierId, ispassed, hurtNum, process, activityId)
    local pb = LProtoHelper.CreateProto(LProtoIds.ProtectCityBattleResultReq)
    pb.activityId = activityId or self._activityId
    pb.barrierId = barrierId
    pb.ispassed = ispassed
    pb.hurtNum = hurtNum
    pb.process = process or 1

    SendMessage(pb, LProtoIds.ProtectCityBattleResultReq)
end

-- 战斗结果 返回
function ModelDefenceWar:OnProtectCityBattleResultResp(pb)
    local stageId = pb.barrierData.barrierId
    local isWin = pb.ispassed == 1
    if pb.barrierData.isPass == 1 then
        self._passMaxStageId = math.max(self._passMaxStageId, stageId)
    end

    local itemList = {}
    local info = gModelGeneral:GetThingsDetailInfoByPb(pb.thingsDetail)
    local allRewardList = info:GetThingsDetailAllRewardList() or {}
    for idx, val in ipairs(allRewardList) do
        table.insert(itemList, val.serverData)
    end

    GF.OpenWnd("UIDefenceWarResult", { stageId = stageId, isWin = isWin, itemList = itemList })
end

-- 活动列表返回
function ModelDefenceWar:OnActivityListChange()
    if not self._firstRequest then
        local list = gModelActivity:GetActivityDataByModelId(self:GetModelId())
        if #list == 0 then
            self._firstRequest = nil
            return
        end

        local activityData = list[1] -- 只会开一个
        self._activityId = activityData.sid

        self._firstRequest = true

        self:ProtectCityInfoReq()
        self:GetWebActivityData()
    end
end

-- 网页数据返回
function ModelDefenceWar:OnActivityConfigData(webData, sid)
    if self._activityId ~= sid then
        return
    end
    if self._needOpenView then
        self._needOpenView = nil
        GF.OpenWnd("UIDefenceWarMain")
    end
end

-- 获取活动modelId
function ModelDefenceWar:GetModelId()
    return ModelActivity.MODEL_ACTIVITY_TYPE_158
end

-- 获取活动数据
function ModelDefenceWar:GetActivityData()
    if self._activityId == 0 then
        local list = gModelActivity:GetActivityDataByModelId(self:GetModelId())
        if #list == 0 then
            return
        end
        local activityData = list[1] -- 只会开一个
        self._activityId = activityData.sid
        return activityData
    end

    local activityData = gModelActivity:GetActivityBySid(self._activityId)
    return activityData
end

-- 获取活动web数据
function ModelDefenceWar:GetWebActivityData()
    local activityData = self:GetActivityData()
    if not activityData then
        return nil
    end

    local activityWebData = gModelActivity:GetWebActivityDataById(activityData.sid)
    return activityWebData
end

-- 打开主界面
function ModelDefenceWar:OpenMainWndByActivityData(activityData)
    self._activityId = activityData.sid

    local activityWebData = self:GetWebActivityData()
    if not activityWebData then
        self._needOpenView = true
    else
        GF.OpenWnd("UIDefenceWarMain")
    end
end

-- 获取空位列表
function ModelDefenceWar:GetEmptyPosList()
    local emptyPosList = {}
    for i = 1, 5 do
        if not self:GetUseRefId(i) then
            table.insert(emptyPosList, i)
        end
    end
    return emptyPosList
end

-- 获取少女上阵refId, nil表示未上阵
function ModelDefenceWar:GetUseRefId(pos)
    for _, v in ipairs(self._formation) do
        if v.site == pos and v.heroId ~= 0 then
            return v.heroId
        end
    end
    return nil
end

-- 返回true,表示少女已上阵
function ModelDefenceWar:HadUsed(heroId)
    for _, v in ipairs(self._formation) do
        if v.heroId == heroId then
            return true
        end
    end
    return false
end

-- 上阵少女，更换位置
function ModelDefenceWar:ChangePos(formPos, toPos)
    local formData, toData
    for _, v in ipairs(self._formation) do
        if v.site == formPos then
            formData = v
        elseif v.site == toPos then
            toData = v
        end
    end

    for _, v in ipairs(self._formation) do
        if v.site == formPos then
            if not toData then
                v.site = toPos
                break
            else
                v.site = toPos
                toData.site = formPos
            end
        end
    end
end

-- 更换上阵少女
function ModelDefenceWar:ChangeHero(pos, heroId)
    for _, v in ipairs(self._formation) do
        if v.site == pos then
            v.heroId = heroId
            break
        end
    end
end

-- 获取一键上阵
function ModelDefenceWar:GetOneKeyUp()
    local list = {}
    for heroId, data in pairs(self._heroMap) do
        table.insert(list, { heroId = heroId, lev = data.lev })
    end
    table.sort(list, function(a, b)
        if a.lev ~= b.lev then
            return a.lev > b.lev
        end
        return a.heroId < b.heroId
    end)

    local dataList = {}
    for k, v in ipairs(list) do
        if k > 5 then
            break
        end
        table.insert(dataList, v.heroId)
    end

    return dataList
end

-- 获取少女等级， 0表示未激活
function ModelDefenceWar:GetHeroLev(heroId)
    local data = self._heroMap[heroId]
    if data then
        return data.lev
    end
    return 0
end

-- 获取当前关卡
function ModelDefenceWar:GetCurStageId()
    local pass = self:GetPassMaxStageId()
    if pass == self:GetMaxStageId() then
        return pass
    end

    if pass == 0 then
        return 1
    end

    return pass + 1
end

-- 获取最大通关关卡
function ModelDefenceWar:GetPassMaxStageId()
    return self._passMaxStageId
end

-- 获取最大关卡
function ModelDefenceWar:GetMaxStageId()
    if not self._maxStageId then
        local list = self:GetStageRefList()
        self._maxStageId = list[#list].refId
    end
    return self._maxStageId
end

-- 获取少女数据列表
function ModelDefenceWar:GetHeroDataList(sort)
    local list = {}
    for heroId in pairs(self._heroRefMap) do
        local tab = {}
        tab.lev = self:GetHeroLev(heroId)
        tab.ref = self:GetHeroRef(heroId, tab.lev)
        table.insert(list, tab)
    end
    if sort then
        table.sort(list, function(a, b)
            if a.lev ~= b.lev then
                return a.lev > b.lev
            end
            if a.ref.quality ~= b.ref.quality then
                return a.ref.quality > b.ref.quality
            end
            return a.ref.refId < b.ref.refId
        end)
    end
    return list
end

-- 获取核心最大血量
function ModelDefenceWar:GetCoreMaxHp()
    local hp = 0
    for _, v in ipairs(self._formation) do
        local heroId = v.heroId
        local lev = self:GetHeroLev(heroId)
        local ref = self:GetHeroLevRef(heroId, lev)
        hp = hp + ref.addattr
    end
    return hp
end

-- 初始核心生命
function ModelDefenceWar:GetInitCoreHp()
    local hp = 0
    local data = self:GetWebActivityData()
    if data then
        hp = data.config.roguelikeHp
    end
    return hp
end


-- 获取布阵列表
function ModelDefenceWar:GetFormationList()
    return self._formation
end

-- true:英雄少女能升级或激活
function ModelDefenceWar:HeroCanUp(heroId, showTips)
    local heroLev = self:GetHeroLev(heroId)
    local heroNextLevRef = self:GetHeroLevRef(heroId, heroLev + 1)
    if not heroNextLevRef then
        if showTips then
            GF.ShowTips(ccClientText(46833))
        end
        return false
    end

    local heroLevRef = self:GetHeroLevRef(heroId, heroLev)
    local itemList = LUtil.GetRefItemDataList(heroLevRef.upNeed)
    for _, item in ipairs(itemList) do
        local needNum = item.itemNum
        local haveNum = gModelItem:GetNumByRefId(item.itemId)
        if haveNum < needNum then
            if showTips then
                local tipsId = heroLev == 0 and 46837 or 46836
                local itemName = gModelItem:GetNameByRefId(item.itemId)
                GF.ShowMessage(ccClientText(tipsId, itemName))
                gModelGeneral:OpenGetWayWnd({ itemId = item.itemId })
                return false
            end

            return false
        end
    end
    return true
end


-- true:有少女能升级或激活
function ModelDefenceWar:HasHeroCanUp()
    for heroId in pairs(self._heroRefMap) do
        if self:HeroCanUp(heroId, false) then
            return true
        end
    end
    return false
end

-- region 配置 ----------------------------------------------------

function ModelDefenceWar:InitRef()
    self:InitHeroRef()
    self:InitHeroLevRef()
    self:InitMonsterGroupRef()
    self:InitSkillRef()
    self:InitStageExpRef()
end

-- 初始化少女配置
function ModelDefenceWar:InitHeroRef()
    local map = {}
    for _, ref in pairs(GameTable.MoeCityHeroRef) do
        if not map[ref.heroId] then
            map[ref.heroId] = {}
        end
        table.insert(map[ref.heroId], ref)
    end
    for _, list in pairs(map) do
        table.sort(list, function(a, b)
            return a.level < b.level
        end)
    end

    self._heroRefMap = map
end

-- 初始化少女等级配置
function ModelDefenceWar:InitHeroLevRef()
    local map = {}
    for _, ref in pairs(GameTable.MoeCityHeroLevelRef) do
        if not map[ref.heroId] then
            map[ref.heroId] = {}
        end
        map[ref.heroId][ref.levelNow] = ref
    end
    self._heroLevRefMap = map
end

-- 初始化怪物组配置
function ModelDefenceWar:InitMonsterGroupRef()
    local map = {}
    for _, ref in pairs(GameTable.MoeCityMonsterGroupRef) do
        if not map[ref.groupId] then
            map[ref.groupId] = {}
        end
        table.insert(map[ref.groupId], ref)
    end

    for _, list in pairs(map) do
        table.sort(list, function(a, b)
            return a.starTime < b.starTime
        end)
    end
    self._monsterGroupRefMap = map
end

-- 初始化技能配置
function ModelDefenceWar:InitSkillRef()
    local map = {}
    for _, ref in pairs(GameTable.MoeCitySkillRef) do
        if not map[ref.skillId] then
            map[ref.skillId] = {}
        end
        map[ref.skillId][ref.level] = ref
    end
    self._skillRefMap = map
end

-- 初始化关卡经验配置
function ModelDefenceWar:InitStageExpRef()
    local list = {}
    for _, ref in pairs(GameTable.MoeCityStageLevelRef) do
        list[ref.level] = ref
    end
    self._stageExpRefList = list
end

-- 获取少女等级
function ModelDefenceWar:GetHeroLevByRefId(refId)
    local ref = GameTable.MoeCityHeroLevelRef[refId]
    return ref.levelNow
end

-- 获取少女卡片配置
function ModelDefenceWar:GetHeroRef(heroId, lev)
    lev = lev or self:GetHeroLev(heroId)
    local list = self._heroRefMap[heroId]
    for k, ref in ipairs(list) do
        if lev < ref.level then
            if k == 1 then
                return list[1]
            else
                return list[k - 1]
            end
        elseif lev == ref.level then
            return ref
        end
    end
    return list[1]
end

-- 获取所有少女卡片配置
function ModelDefenceWar:GetHeroRefList(heroId)
    return self._heroRefMap[heroId]
end

-- 获取少女等级配置
function ModelDefenceWar:GetHeroLevRef(heroId, lev)
    return self._heroLevRefMap[heroId][lev]
end

-- 获取关卡配置列表
function ModelDefenceWar:GetStageRefList()
    return GameTable.MoeCityStageRef
end

-- 获取关卡配置
function ModelDefenceWar:GetStageRef(stageId)
    local ref = GameTable.MoeCityStageRef[stageId]
    return ref
end

-- 获取消耗道具数据 (注意要判空)
function ModelDefenceWar:GetCostItemData()
    if not self._costItemId then
        local activityWebData = self:GetWebActivityData()
        if activityWebData then
            local config = activityWebData.config
            self._costItemId = config.roguelikeItem
            self._costItemMaxNum = config.roguelikeStaminaMax
            self._recoverTime = config.roguelikeStaminaTime
        end
    end

    return self._costItemId, self._costItemMaxNum, self._recoverTime
end

-- 获取下次体力恢复时间
function ModelDefenceWar:GetNextRecoverTime()
    return self._nextRecoverTime
end

-- 获取怪物配置
function ModelDefenceWar:GetMonsterRef(refId)
    local ref = GameTable.MoeCityMonsterRef[refId]
    return ref
end

-- 获取怪物组配置
function ModelDefenceWar:GetMonsterGroupRef(refId)
    local ref = GameTable.MoeCityMonsterGroupRef[refId]
    return ref
end

-- 获取怪物组配置列表
function ModelDefenceWar:GetMonsterGroupRefList(groupId)
    return self._monsterGroupRefMap[groupId] or {}
end

-- 获取关卡的怪物列表
function ModelDefenceWar:GetMonsterList(refId, ref)
    if not ref then
        ref = self:GetStageRef(refId)
    end

    local monsterMap = {}
    local groupId = ref.monster
    local list = self:GetMonsterListFromMonsterGroup(groupId)
    for _, tab in ipairs(list) do
        for _, v in ipairs(tab) do
            monsterMap[v.monsterRefId] = true
        end
    end

    local monsterList = {}
    for refId in pairs(monsterMap) do
        table.insert(monsterList, refId)
    end
    table.sort(monsterList, function(a, b) return a < b end)
    return monsterList
end

-- 获取怪物组的怪物配置列表
function ModelDefenceWar:GetMonsterListFromMonsterGroup(groupId)
    local groupRefList = self:GetMonsterGroupRefList(groupId)
    local dataList = {}
    for _, groupRef in ipairs(groupRefList) do
        local list = {}
        for i = 1, 5 do
            local monsterRefId = groupRef["monster" .. i]
            if monsterRefId and monsterRefId > 0 then
                local posStr = groupRef["coord" .. i]
                local pos = nil
                if posStr and posStr ~= "" then
                    local tab = string.split(posStr, ",")
                    pos = Vector3(tonumber(tab[1]), tonumber(tab[2]), 0)
                end
                table.insert(list, { groupRefId = groupRef.refId, monsterRefId = monsterRefId, pos = pos })
            end
        end
        table.insert(dataList, list)
    end

    return dataList
end

-- 获取技能配置
function ModelDefenceWar:GetSkillRef(skillId, lev)
    return self._skillRefMap[skillId][lev]
end

-- true:已满级
function ModelDefenceWar:IsMaxLev(skillId, lev)
    local ref = self:GetSkillRef(skillId, lev + 1)
    return ref == nil
end

-- 获取等级
function ModelDefenceWar:GetLevByExp(exp, lev)
    if exp == 0 then
        return 1
    end

    for i = lev, #self._stageExpRefList do
        local ref = self._stageExpRefList[i]
        if exp < ref.exp then
            return i
        end
    end
    return #self._stageExpRefList
end

-- 获取当前等级经验
function ModelDefenceWar:GetCurExp(lev)
    local ref = self._stageExpRefList[lev]
    return ref.exp
end

-- 获取怪物生成初始高度
function ModelDefenceWar:GetMonsterInitHeight()
    if not self._monsterInitY then
        self._monsterInitY = GameTable.MoeCityConfigRef.initialDistance
    end
    return self._monsterInitY
end

-- 获取技能攻击高度
function ModelDefenceWar:GetSkillAttackHeight()
    if not self._skillAttackY then
        self._skillAttackY = GameTable.MoeCityConfigRef.attackDistance
    end
    return self._skillAttackY
end

-- endregion 配置 ----------------------------------------------------

-- 显示技能选择
function ModelDefenceWar:ShowSkillSelect(dataList)
    GF.OpenWnd("UIDefenceWarSkillSelect", { dataList = dataList })
end

-- 绘制卡片
function ModelDefenceWar:DrawCard(wnd, rootTrans, param)
    local instanceID = rootTrans:GetInstanceID()
    local itemCache = wnd:GetComponentCache(instanceID)
    if not itemCache then
        itemCache = {}
        itemCache.icon = CS.FindTrans(rootTrans, "Bg/Icon")

        wnd:SetComponentCache(instanceID, itemCache)
    end

    local heroId = param.heroId
    local lev = param.lev or 0
    local ref = self:GetHeroRef(heroId, lev)
    wnd:SetWndEasyImage(itemCache.icon, ref.icon)
end

-- 进入保存战地图
function ModelDefenceWar:EnterMap(stageId)
    gLGameUI:CloseAllButExcept({
        -- ["WndMatchThreeGameEnter"] = true,
    })
    GF.ChangeMap("LDefenceWarMap", nil, { stageId = stageId })
end

-- 个人log
function ModelDefenceWar:Log(str)
    local strInfo = ""

    local traceback = ""
    if CS.IsUnityEdit() then
        traceback = debug.traceback()
    end
    print("````" .. strInfo .. "  " .. str .. "  \n" .. traceback)
end

return ModelDefenceWar
